import "./styles/LibrarianBooks.css";
import { useNavigate, useLocation } from "react-router-dom";

function LibrarianBooks() {
  const location = useLocation();
  const genre = location.state?.genre || "Literature";
  const navigate = useNavigate();

  return (
    <div className="dashboard-page">
      <h1 className="dashboard-title">
        Manage {genre} Books
      </h1>

      <div className="dashboard-center">
       <div
  className="dash-card"
  onClick={() =>
    navigate("/librarian-books", {
      state: { genre }
    })
  }
>
  <i class="bi bi-view-list"></i> View {genre} Books
</div>


        <div
  className="dash-card"
  onClick={() =>
    navigate("/add-book", { state: { genre } })
  }
>
  <i class="bi bi-plus-lg"></i> Add New Book
</div>

        <div className="dash-card"><i class="bi bi-pencil-square"></i> Update Book Status</div>
        <div className="dash-card"><i class="bi bi-x-lg"></i> Remove Book</div>
      </div>
    </div>
  );
}

export default LibrarianBooks;
